mapper.select:
SELECT CH_RM_SN
FROM CHAT_ROOM
WHERE TRD_SN = #{tradeId}

mapper.insert:
INSERT INTO CHAT_ROOM (
    TRD_SN,
    CH_RM_STATUS_CD
)
VALUES (
    #{tradeId},
    #{roomStatus}
)

mapper.select:
SELECT r.CH_RM_SN AS roomId, t.TRD_SN AS tradeId, CASE WHEN t.BYPR_USR_SN = #{userId} THEN seller.USR_NM ELSE buyer.USR_NM END AS counterpartNickname, p.PRD_NM AS productName, r.CH_RM_STATUS_CD AS roomStatus, ( SELECT m.CH_MSG_CN FROM CHAT_MESSAGE m WHERE m.CH_RM_SN = r.CH_RM_SN ORDER BY m.CH_MSG_REG_DT DESC, m.CH_MSG_SN DESC LIMIT 1 ) AS lastMessage, ( SELECT m.CH_MSG_REG_DT FROM CHAT_MESSAGE m WHERE m.CH_RM_SN = r.CH_RM_SN ORDER BY m.CH_MSG_REG_DT DESC, m.CH_MSG_SN DESC LIMIT 1 ) AS latestMessageAt, ( SELECT COUNT(*) FROM CHAT_MESSAGE m WHERE m.CH_RM_SN = r.CH_RM_SN AND m.USR_SN != #{userId} AND m.CH_MSG_READ_YN = 'N' ) AS unreadCount FROM CHAT_ROOM r JOIN TRADE t ON t.TRD_SN = r.TRD_SN JOIN PRODUCT p ON p.PRD_SN = t.PRD_SN JOIN USERS seller ON seller.USR_SN = t.SLLR_USR_SN JOIN USERS buyer ON buyer.USR_SN = t.BYPR_USR_SN WHERE t.TRD_TYPE_CD = 'TRDC0001' AND p.PRD_TRD_METHOD_CD = 'TRDC0010' AND (t.SLLR_USR_SN = #{userId} OR t.BYPR_USR_SN = #{userId})
AND t.TRD_SN = #{tradeId}
ORDER BY latestMessageAt DESC, r.CH_RM_SN DESC

mapper.update:
UPDATE CHAT_MESSAGE
SET CH_MSG_READ_YN = 'Y'
WHERE CH_RM_SN = #{roomId}
  AND USR_SN != #{userId}
  AND CH_MSG_READ_YN = 'N'

mapper.insert:
